WITH fn AS (SELECT p.oid, p.proacl, p.proowner, pg_get_functiondef(p.oid) AS definition FROM pg_proc p WHERE p.oid = to_regprocedure('public.undo_outbound_delivery(uuid)')) SELECT audit_issue, detail FROM (SELECT 'function_missing'::text AS audit_issue, 'Thieu RPC undo_outbound_delivery(uuid)'::text AS detail WHERE NOT EXISTS (SELECT 1 FROM fn) UNION ALL SELECT 'legacy_logic_still_active', 'RPC cu van con lenh sua giao dich kho hoac ke hoach' WHERE EXISTS (SELECT 1 FROM fn WHERE definition ILIKE ('%UP' || 'DATE public.inventory_transactions%') OR definition ILIKE ('%UP' || 'DATE public.delivery_plans%')) UNION ALL SELECT 'blocking_message_missing', 'RPC cu chua bi khoa ve Nhat ky giao hang' WHERE EXISTS (SELECT 1 FROM fn WHERE definition NOT ILIKE '%Huy tung ma tai Ke hoach giao hang da tat%') UNION ALL SELECT 'public_can_execute', 'PUBLIC van co quyen goi RPC' WHERE EXISTS (SELECT 1 FROM fn CROSS JOIN LATERAL aclexplode(COALESCE(fn.proacl, acldefault('f', fn.proowner))) acl WHERE acl.grantee = 0 AND acl.privilege_type = 'EXECUTE') UNION ALL SELECT 'anon_can_execute', 'anon van co quyen goi RPC' WHERE to_regprocedure('public.undo_outbound_delivery(uuid)') IS NOT NULL AND has_function_privilege('anon', 'public.undo_outbound_delivery(uuid)', 'EXECUTE') UNION ALL SELECT 'authenticated_cannot_execute', 'authenticated khong nhan duoc thong bao khoa ro rang' WHERE to_regprocedure('public.undo_outbound_delivery(uuid)') IS NOT NULL AND NOT has_function_privilege('authenticated', 'public.undo_outbound_delivery(uuid)', 'EXECUTE')) problems ORDER BY audit_issue;
